#include<iostream>#include<vector>#include<map>#define ll long long using namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<int>a(n);        map<ll,ll>freq;        for(int i=0;i<n;i++){            cin>>a[i];            freq[a[i]]++;        }                ll ans=0;        ll prev=-1;        ll prev_freq=0;        for(auto const& p : freq){            ll val = p.first;            ll cnt = p.second;             if(val!= prev + 1){                ans+=cnt;            }            else{                if(cnt>prev_freq){                    ans+=cnt - prev_freq;                }            }            prev= val;            prev_freq= cnt;        }        cout<<ans<<"\n";    } }